#include "limitlit/graphics/BitmapFont.hpp"
namespace LimitLit
{
std::array<uint8_t,7> BitmapFont::Glyph(char c)
{
    if(c>='a'&&c<='z') c=static_cast<char>(c-'a'+'A');
    switch(c)
    {
        case 'A':return{0x0E,0x11,0x11,0x1F,0x11,0x11,0x11}; case 'B':return{0x1E,0x11,0x11,0x1E,0x11,0x11,0x1E}; case 'C':return{0x0E,0x11,0x10,0x10,0x10,0x11,0x0E}; case 'D':return{0x1E,0x11,0x11,0x11,0x11,0x11,0x1E}; case 'E':return{0x1F,0x10,0x10,0x1E,0x10,0x10,0x1F}; case 'F':return{0x1F,0x10,0x10,0x1E,0x10,0x10,0x10}; case 'G':return{0x0E,0x11,0x10,0x17,0x11,0x11,0x0E}; case 'H':return{0x11,0x11,0x11,0x1F,0x11,0x11,0x11}; case 'I':return{0x1F,0x04,0x04,0x04,0x04,0x04,0x1F}; case 'J':return{0x01,0x01,0x01,0x01,0x11,0x11,0x0E}; case 'K':return{0x11,0x12,0x14,0x18,0x14,0x12,0x11}; case 'L':return{0x10,0x10,0x10,0x10,0x10,0x10,0x1F}; case 'M':return{0x11,0x1B,0x15,0x15,0x11,0x11,0x11}; case 'N':return{0x11,0x19,0x15,0x13,0x11,0x11,0x11}; case 'O':return{0x0E,0x11,0x11,0x11,0x11,0x11,0x0E}; case 'P':return{0x1E,0x11,0x11,0x1E,0x10,0x10,0x10}; case 'Q':return{0x0E,0x11,0x11,0x11,0x15,0x12,0x0D}; case 'R':return{0x1E,0x11,0x11,0x1E,0x14,0x12,0x11}; case 'S':return{0x0F,0x10,0x10,0x0E,0x01,0x01,0x1E}; case 'T':return{0x1F,0x04,0x04,0x04,0x04,0x04,0x04}; case 'U':return{0x11,0x11,0x11,0x11,0x11,0x11,0x0E}; case 'V':return{0x11,0x11,0x11,0x11,0x11,0x0A,0x04}; case 'W':return{0x11,0x11,0x11,0x15,0x15,0x15,0x0A}; case 'X':return{0x11,0x11,0x0A,0x04,0x0A,0x11,0x11}; case 'Y':return{0x11,0x11,0x0A,0x04,0x04,0x04,0x04}; case 'Z':return{0x1F,0x01,0x02,0x04,0x08,0x10,0x1F};
        case '0':return{0x0E,0x11,0x13,0x15,0x19,0x11,0x0E}; case '1':return{0x04,0x0C,0x04,0x04,0x04,0x04,0x0E}; case '2':return{0x0E,0x11,0x01,0x02,0x04,0x08,0x1F}; case '3':return{0x1E,0x01,0x01,0x0E,0x01,0x01,0x1E}; case '4':return{0x02,0x06,0x0A,0x12,0x1F,0x02,0x02}; case '5':return{0x1F,0x10,0x10,0x1E,0x01,0x01,0x1E}; case '6':return{0x0E,0x10,0x10,0x1E,0x11,0x11,0x0E}; case '7':return{0x1F,0x01,0x02,0x04,0x08,0x08,0x08}; case '8':return{0x0E,0x11,0x11,0x0E,0x11,0x11,0x0E}; case '9':return{0x0E,0x11,0x11,0x0F,0x01,0x01,0x0E};
        case ' ':return{0,0,0,0,0,0,0}; case '.':return{0,0,0,0,0,0x0C,0x0C}; case ':':return{0,0x0C,0x0C,0,0x0C,0x0C,0}; case '-':return{0,0,0,0x1F,0,0,0}; case '_':return{0,0,0,0,0,0,0x1F}; case '/':return{0x01,0x01,0x02,0x04,0x08,0x10,0x10}; case '>':return{0x10,0x08,0x04,0x02,0x04,0x08,0x10};
        default:return{0x1F,0x11,0x15,0x15,0x11,0x11,0x1F};
    }
}
}
